import json
import os
import re
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

ALLOWED_ORIGINS = os.environ.get(
    "ALLOWED_ORIGINS",
    "http://localhost:3000,http://localhost:5173,https://staging.example.com,https://app.example.com"
).split(",")

ALLOWED_METHODS = "GET,OPTIONS"
ALLOWED_HEADERS = "Content-Type,Authorization,X-Requested-With"
MAX_AGE = "3600"


def get_allowed_origin(request_origin):
    """Validate the request origin against the allowlist."""
    if not request_origin:
        return None

    request_origin = request_origin.strip()

    for allowed in ALLOWED_ORIGINS:
        allowed = allowed.strip()
        if request_origin == allowed:
            return request_origin

    return None


def build_cors_headers(event):
    """Build CORS headers based on validated origin."""
    headers = event.get("headers", {}) or {}

    request_origin = headers.get("origin") or headers.get("Origin", "")

    validated_origin = get_allowed_origin(request_origin)

    cors_headers = {
        "Vary": "Origin",
        "X-Content-Type-Options": "nosniff",
        "X-Frame-Options": "DENY",
        "Strict-Transport-Security": "max-age=31536000; includeSubDomains",
        "Cache-Control": "no-store",
        "Content-Type": "application/json",
    }

    if validated_origin:
        cors_headers["Access-Control-Allow-Origin"] = validated_origin
        cors_headers["Access-Control-Allow-Methods"] = ALLOWED_METHODS
        cors_headers["Access-Control-Allow-Headers"] = ALLOWED_HEADERS
        cors_headers["Access-Control-Max-Age"] = MAX_AGE
        cors_headers["Access-Control-Allow-Credentials"] = "false"

    return cors_headers


def validate_user_id(user_id):
    """Validate user_id to prevent injection attacks."""
    if not user_id:
        return None
    if not re.match(r'^[a-zA-Z0-9_-]{1,64}$', user_id):
        return None
    return user_id


def get_user_data(user_id):
    """Retrieve user data. Replace with actual database lookup."""
    mock_users = {
        "user-1": {
            "id": "user-1",
            "name": "Alice Johnson",
            "email": "alice@example.com",
            "role": "developer",
        },
        "user-2": {
            "id": "user-2",
            "name": "Bob Smith",
            "email": "bob@example.com",
            "role": "designer",
        },
    }
    return mock_users.get(user_id)


def lambda_handler(event, context):
    """Main Lambda handler for API Gateway proxy integration."""
    logger.info("Received request: method=%s, path=%s",
                event.get("httpMethod"), event.get("path"))

    cors_headers = build_cors_headers(event)

    http_method = event.get("httpMethod", "")

    if http_method == "OPTIONS":
        return {
            "statusCode": 204,
            "headers": cors_headers,
            "body": "",
        }

    if http_method != "GET":
        return {
            "statusCode": 405,
            "headers": cors_headers,
            "body": json.dumps({"error": "Method not allowed"}),
        }

    try:
        path_parameters = event.get("pathParameters") or {}
        raw_user_id = path_parameters.get("userId")

        query_params = event.get("queryStringParameters") or {}
        if not raw_user_id:
            raw_user_id = query_params.get("userId")

        if raw_user_id:
            user_id = validate_user_id(raw_user_id)
            if not user_id:
                return {
                    "statusCode": 400,
                    "headers": cors_headers,
                    "body": json.dumps({"error": "Invalid user ID format"}),
                }

            user_data = get_user_data(user_id)
            if not user_data:
                return {
                    "statusCode": 404,
                    "headers": cors_headers,
                    "body": json.dumps({"error": "User not found"}),
                }

            return {
                "statusCode": 200,
                "headers": cors_headers,
                "body": json.dumps({"data": user_data}),
            }

        else:
            users = []
            for uid in ["user-1", "user-2"]:
                user = get_user_data(uid)
                if user:
                    users.append({"id": user["id"], "name": user["name"], "role": user["role"]})

            return {
                "statusCode": 200,
                "headers": cors_headers,
                "body": json.dumps({"data": users}),
            }

    except Exception:
        logger.exception("Unexpected error processing request")
        return {
            "statusCode": 500,
            "headers": cors_headers,
            "body": json.dumps({"error": "Internal server error"}),
        }